export function seedUsExecutiveOrders(db) {
    console.log('  Seeding US executive orders...');
    const insertSource = db.prepare(`INSERT INTO sources (title, short_title, source_type, organization, adoption_date, entry_into_force_date, status, signatories_count, url, notes)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`);
    const insertArticle = db.prepare(`INSERT INTO articles (source_id, article_number, title, content, chapter, part, keywords)
     VALUES (?, ?, ?, ?, ?, ?, ?)`);
    // EO 14028
    const eo14028 = insertSource.run('Executive Order 14028 — Improving the Nation\'s Cybersecurity', 'EO 14028', 'executive_order', 'President of the United States', '2021-05-12', '2021-05-12', 'in_force', null, 'https://www.whitehouse.gov/briefing-room/presidential-actions/2021/05/12/executive-order-on-improving-the-nations-cybersecurity/', 'Issued after SolarWinds and Colonial Pipeline incidents. Mandates zero trust architecture, software supply chain security, endpoint detection, and incident response improvements across federal agencies.');
    const eo14028Id = Number(eo14028.lastInsertRowid);
    const eo14028Articles = [
        { num: 'Section 1', title: 'Policy', content: 'The United States faces persistent and increasingly sophisticated malicious cyber campaigns that threaten the public sector, the private sector, and ultimately the American people\'s security and privacy. The Federal Government must improve its efforts to identify, deter, protect against, detect, and respond to these actions and actors. Incremental improvements will not give us the security we need; instead, the Federal Government needs to make bold changes and significant investments in order to defend the vital institutions that underpin the American way of life.', ch: 'EO 14028', part: null, kw: 'policy,federal government,cybersecurity,bold changes' },
        { num: 'Section 2', title: 'Removing barriers to sharing threat information', content: 'The Federal Government must ensure that IT Service Providers sharing information with the Federal Government can do so without undue concern about potentially being held liable. IT Service Providers entering into contracts with the Federal Government must be required to share cyber threat and incident information. Contracting agencies must remove contractual barriers to sharing threat and incident information.', ch: 'EO 14028', part: null, kw: 'information sharing,threat information,IT service providers,liability,contracts' },
        { num: 'Section 3', title: 'Modernizing Federal Government cybersecurity', content: 'The Federal Government must adopt security best practices, advance toward Zero Trust Architecture, accelerate movement to secure cloud services, centralize and streamline access to cybersecurity data, and invest in both technology and personnel to match these modernization goals. Within 180 days, each agency head shall develop a plan to implement Zero Trust Architecture.', ch: 'EO 14028', part: null, kw: 'zero trust,cloud services,modernization,cybersecurity data' },
        { num: 'Section 4', title: 'Enhancing software supply chain security', content: 'The Federal Government must ensure the security and integrity of the software supply chain. NIST shall publish guidelines for enhancing software supply chain security, including criteria for secure software development environments, automated tools for source code supply chain verification, and a definition of "critical software." NTIA shall publish minimum elements for a Software Bill of Materials (SBOM). Within 180 days, the Secretary of Commerce shall publish a definition of the term "critical software" and produce guidance identifying practices enhancing the security of the software supply chain.', ch: 'EO 14028', part: null, kw: 'software supply chain,SBOM,NIST,critical software,secure development' },
        { num: 'Section 5', title: 'Establishing a Cyber Safety Review Board', content: 'The Secretary of Homeland Security, in consultation with the Attorney General, shall establish a Cyber Safety Review Board. The Board shall review and assess significant cyber incidents affecting Federal Civilian Executive Branch Information Systems or non-Federal systems. The Board shall make recommendations for improving cybersecurity and incident response practices based on lessons learned.', ch: 'EO 14028', part: null, kw: 'Cyber Safety Review Board,CSRB,incident review,lessons learned' },
        { num: 'Section 6', title: 'Standardizing Federal Government playbook for incident response', content: 'The cybersecurity vulnerability and incident response procedures currently used to identify, remediate, and recover from vulnerabilities and incidents affecting Federal information systems vary across agencies. Standardizing common processes will facilitate better and more coordinated information sharing and response. The Secretary of Homeland Security shall develop a standard set of operational procedures (playbook) to be used in planning and conducting cybersecurity vulnerability and incident response activity.', ch: 'EO 14028', part: null, kw: 'incident response,playbook,standardization,vulnerability response' },
        { num: 'Section 7', title: 'Improving detection of cybersecurity vulnerabilities and incidents', content: 'The Federal Government shall deploy an Endpoint Detection and Response (EDR) initiative across Federal agencies to support proactive detection of cybersecurity incidents within Federal Government infrastructure, active cyber hunting, containment and remediation, and incident response.', ch: 'EO 14028', part: null, kw: 'EDR,endpoint detection,proactive detection,cyber hunting' },
        { num: 'Section 8', title: 'Improving investigative and remediation capabilities', content: 'Federal agencies shall maintain and store logs necessary for detecting, investigating, and remediating cybersecurity incidents. Network and system logs shall be retained for a minimum period as defined by NIST and CISA guidance. Event logs shall be maintained in a format that allows for centralized access and analysis.', ch: 'EO 14028', part: null, kw: 'logging,investigation,remediation,log retention,centralized analysis' },
        { num: 'Section 9', title: 'National security systems', content: 'Within 60 days, the Secretary of Defense, the Director of National Intelligence, and the Committee on National Security Systems shall adopt National Security Memorandum requirements equivalent to those in this order for National Security Systems.', ch: 'EO 14028', part: null, kw: 'national security systems,NSS,defense,intelligence' },
        { num: 'Section 10', title: 'Consumer labeling for IoT and software', content: 'Within 270 days, the Director of NIST shall identify IoT cybersecurity criteria for a consumer labeling program, and shall consider whether such a consumer labeling program may be extended to cover software development practices.', ch: 'EO 14028', part: null, kw: 'IoT,consumer labeling,software labeling,NIST criteria' },
        { num: 'Section 11', title: 'Definitions', content: 'Defines key terms including "agencies," "Federal Civilian Executive Branch Agencies," "Federal Civilian Executive Branch Information Systems," "Federal Information Systems," "Zero Trust Architecture," and "Software Bill of Materials."', ch: 'EO 14028', part: null, kw: 'definitions,zero trust architecture,SBOM,federal systems' },
    ];
    // EO 13800
    const eo13800 = insertSource.run('Executive Order 13800 — Strengthening the Cybersecurity of Federal Networks and Critical Infrastructure', 'EO 13800', 'executive_order', 'President of the United States', '2017-05-11', '2017-05-11', 'in_force', null, 'https://www.federalregister.gov/documents/2017/05/16/2017-10004/strengthening-the-cybersecurity-of-federal-networks-and-critical-infrastructure', 'Required federal agencies to implement NIST Cybersecurity Framework. Mandated modernization of federal IT. Preceded EO 14028.');
    const eo13800Id = Number(eo13800.lastInsertRowid);
    const eo13800Articles = [
        { num: 'Section 1', title: 'Cybersecurity of Federal Networks', content: 'The executive branch operates its IT on behalf of the American people. The President will hold heads of executive departments and agencies accountable for managing cybersecurity risk to their enterprises. Agency heads must use The Framework for Improving Critical Infrastructure Cybersecurity (the NIST Framework) to manage cybersecurity risk. Each agency head shall provide a risk management report to the Secretary of Homeland Security and the Director of OMB within 90 days.', ch: 'EO 13800', part: null, kw: 'NIST Framework,accountability,risk management,federal networks' },
        { num: 'Section 2', title: 'Cybersecurity of critical infrastructure', content: 'The executive branch will use its authorities and capabilities to support the cybersecurity risk management efforts of the owners and operators of the Nation\'s critical infrastructure. The Secretary of Homeland Security, in coordination with the Secretary of Defense and other agency heads, shall identify authorities and capabilities that agencies could employ to support the cybersecurity efforts of critical infrastructure entities.', ch: 'EO 13800', part: null, kw: 'critical infrastructure,risk management,owners and operators' },
        { num: 'Section 3', title: 'Cybersecurity for the Nation', content: 'The executive branch shall promote an open, interoperable, reliable, and secure internet. The Secretaries of State, Treasury, Defense, Commerce, and Homeland Security shall develop options for deterrence and protective capabilities for the Nation\'s critical infrastructure. Reports on international cybersecurity priorities, deterrence policy, and workforce development shall be prepared.', ch: 'EO 13800', part: null, kw: 'open internet,deterrence,international priorities,workforce' },
        { num: 'Section 4', title: 'IT modernization', content: 'Effective immediately, each agency head shall show preference in procurement for shared IT services, including email, cloud, and cybersecurity services, to the extent permitted by law. The Director of the American Technology Council shall coordinate a report to the President on IT modernization.', ch: 'EO 13800', part: null, kw: 'IT modernization,shared services,cloud,procurement' },
    ];
    // CISA Act 2018
    const cisaAct = insertSource.run('Cybersecurity and Infrastructure Security Agency Act of 2018', 'CISA Act 2018', 'executive_order', 'United States Congress', '2018-11-16', '2018-11-16', 'in_force', null, 'https://www.congress.gov/bill/115th-congress/house-bill/3359', 'Established CISA as a standalone federal agency within DHS. Renamed the National Protection and Programs Directorate (NPPD) to the Cybersecurity and Infrastructure Security Agency.');
    const cisaActId = Number(cisaAct.lastInsertRowid);
    const cisaArticles = [
        { num: 'Section 2201', title: 'Establishment of CISA', content: 'The National Protection and Programs Directorate of the Department of Homeland Security is redesignated as the Cybersecurity and Infrastructure Security Agency. CISA shall be headed by a Director, appointed by the President. The Agency shall be responsible for leading the national effort to understand, manage, and reduce risk to our cyber and physical infrastructure.', ch: 'CISA Act', part: null, kw: 'CISA,establishment,DHS,Director,infrastructure security' },
        { num: 'Section 2202', title: 'CISA responsibilities', content: 'CISA shall: (1) lead cybersecurity and critical infrastructure security programs, operations, and associated policy; (2) coordinate with Federal entities and non-Federal entities, including the owners and operators of critical infrastructure; (3) carry out the cybersecurity and infrastructure security activities of the Department; (4) upon request, provide analyses, expertise, and other technical assistance to critical infrastructure owners and operators.', ch: 'CISA Act', part: null, kw: 'responsibilities,critical infrastructure,coordination,technical assistance' },
        { num: 'Section 2203', title: 'Divisions', content: 'CISA shall include: the Cybersecurity Division (led by an Executive Assistant Director); the Infrastructure Security Division (led by an Executive Assistant Director); the Emergency Communications Division (led by an Executive Assistant Director).', ch: 'CISA Act', part: null, kw: 'divisions,cybersecurity division,infrastructure security,emergency communications' },
        { num: 'Section 2209', title: 'Information sharing', content: 'The Secretary of Homeland Security shall develop policies, procedures, and guidelines for sharing cyber threat indicators and defensive measures with other Federal entities, state and local governments, and the private sector. CISA shall operate the Automated Indicator Sharing (AIS) capability to enable real-time sharing of cyber threat indicators.', ch: 'CISA Act', part: null, kw: 'information sharing,threat indicators,AIS,defensive measures,real-time' },
        { num: 'Section 2215', title: 'Joint Cyber Planning Office', content: 'There is established within CISA a Joint Cyber Planning Office to coordinate cyber defense planning and operations across Federal civilian agencies, the intelligence community, law enforcement, the private sector, and international partners.', ch: 'CISA Act', part: null, kw: 'Joint Cyber Planning Office,coordination,defense planning' },
    ];
    const insertMany = db.transaction(() => {
        for (const art of eo14028Articles) {
            insertArticle.run(eo14028Id, art.num, art.title, art.content, art.ch, art.part, art.kw);
        }
        for (const art of eo13800Articles) {
            insertArticle.run(eo13800Id, art.num, art.title, art.content, art.ch, art.part, art.kw);
        }
        for (const art of cisaArticles) {
            insertArticle.run(cisaActId, art.num, art.title, art.content, art.ch, art.part, art.kw);
        }
    });
    insertMany();
    console.log(`    EO 14028: ${eo14028Articles.length} sections`);
    console.log(`    EO 13800: ${eo13800Articles.length} sections`);
    console.log(`    CISA Act: ${cisaArticles.length} sections`);
}
